'use strict';
if('serviceWorker'in navigator)window.addEventListener('load',()=>navigator.serviceWorker.register('service-worker.js').then(r=>console.log('SW:',r.scope)).catch(e=>console.error('SW erro:',e)));
let _prompt=null;
const _btn=document.getElementById('installBtn');
window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();_prompt=e;_btn.style.display='block'});
_btn.addEventListener('click',async()=>{if(!_prompt)return;_prompt.prompt();const{outcome}=await _prompt.userChoice;_prompt=null;_btn.style.display='none'});
window.addEventListener('appinstalled',()=>{_btn.style.display='none';_prompt=null});
const KEY='diario_entradas';
const load=()=>{try{return JSON.parse(localStorage.getItem(KEY))||[]}catch{return[]}};
const save=d=>localStorage.setItem(KEY,JSON.stringify(d));
const esc=s=>String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
const fmt=d=>{if(!d)return'';const[y,m,dd]=d.split('-');return new Date(y,m-1,dd).toLocaleDateString('pt-BR',{day:'2-digit',month:'long',year:'numeric'})};
function render(){const entries=load();const list=document.getElementById('entriesList');const count=document.getElementById('entryCount');count.textContent=entries.length;if(!entries.length){list.innerHTML='<div class="empty-state"><span class="empty-icon" aria-hidden="true">🌊</span><p>Nenhuma entrada ainda.<br/>Comece registrando seu dia.</p></div>';return}list.innerHTML=entries.slice().reverse().map(e=>`<div class="entry-card"><div class="entry-header"><span class="entry-title">${esc(e.title)}</span><button class="delete-btn" title="Remover" data-id="${e.id}">✕</button></div>${e.date?`<div class="entry-date">${fmt(e.date)}</div>`:''}<div class="entry-desc">${esc(e.desc)}</div></div>`).join('');list.querySelectorAll('.delete-btn').forEach(b=>b.addEventListener('click',()=>del(b.dataset.id)))}
function del(id){if(!confirm('Remover esta entrada?'))return;save(load().filter(e=>e.id!==id));render()}
document.getElementById('addBtn').addEventListener('click',()=>{const t=document.getElementById('entryTitle').value.trim();const d=document.getElementById('entryDate').value;const desc=document.getElementById('entryDesc').value.trim();if(!t&&!desc){alert('Preencha ao menos o título ou a descrição.');return}const entries=load();entries.push({id:Date.now().toString(),title:t||'Sem título',date:d,desc});save(entries);document.getElementById('entryTitle').value='';document.getElementById('entryDate').value='';document.getElementById('entryDesc').value='';render()});
document.getElementById('entryDate').valueAsDate=new Date();
render();